  export default "import * as React from 'react'\nimport { Graph } from '@antv/x6'\nimport { MiniMap } from '@antv/x6-plugin-minimap'\nimport { Scroller } from '@antv/x6-plugin-scroller'\nimport { Radio } from 'antd'\nimport { SimpleNodeView } from './simple-view'\nimport './index.less'\n\nconst options = [\n  { label: '简单视图', value: 'simple' },\n  { label: '详细视图', value: 'detailed' },\n]\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private minimapContainer: HTMLDivElement\n  private graph: Graph\n\n  componentDidMount() {\n    this.graph = new Graph({\n      container: this.container,\n      width: 600,\n      height: 320,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    this.graph.use(\n      new Scroller({\n        enabled: true,\n        pageVisible: true,\n        pageBreak: false,\n        pannable: true,\n      }),\n    )\n    this.graph.use(\n      new MiniMap({\n        container: this.minimapContainer,\n        width: 200,\n        height: 160,\n        padding: 10,\n      }),\n    )\n\n    this.graph.addNode({\n      x: 200,\n      y: 100,\n      width: 100,\n      height: 40,\n      label: 'Rect',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const source = this.graph.addNode({\n      x: 32,\n      y: 32,\n      width: 100,\n      height: 40,\n      label: 'Hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const target = this.graph.addNode({\n      shape: 'circle',\n      x: 160,\n      y: 180,\n      width: 60,\n      height: 60,\n      label: 'World',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n        },\n      },\n    })\n\n    this.graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n  }\n\n  onMinimapViewChange = (val: string) => {\n    this.graph.disposePlugins('minimap')\n    if (val === 'simple') {\n      this.graph.use(\n        new MiniMap({\n          container: this.minimapContainer,\n          width: 200,\n          height: 160,\n          padding: 10,\n          graphOptions: {\n            createCellView(cell) {\n              // 可以返回三种类型数据\n              // 1. null: 不渲染\n              // 2. undefined: 使用 X6 默认渲染方式\n              // 3. CellView: 自定义渲染\n              if (cell.isEdge()) {\n                return null\n              }\n              if (cell.isNode()) {\n                return SimpleNodeView\n              }\n            },\n          },\n        }),\n      )\n    } else {\n      this.graph.use(\n        new MiniMap({\n          container: this.minimapContainer,\n          width: 200,\n          height: 160,\n          padding: 10,\n        }),\n      )\n    }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  refMiniMapContainer = (container: HTMLDivElement) => {\n    this.minimapContainer = container\n  }\n\n  render() {\n    return (\n      <div className=\"minimap-app\">\n        <div className=\"app-btns\">\n          <Radio.Group\n            options={options}\n            onChange={(e) => this.onMinimapViewChange(e.target.value)}\n            defaultValue={'detailed'}\n            optionType=\"button\"\n          />\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n        <div className=\"app-minimap\" ref={this.refMiniMapContainer} />\n      </div>\n    )\n  }\n}\n";;
  