  export default "import React from 'react'\nimport { Checkbox, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (res: State) => void\n}\n\nexport interface State {\n  allowBlank: boolean\n  allowMulti: boolean\n  allowLoop: boolean\n  allowNode: boolean\n  allowEdge: boolean\n  allowPort: boolean\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    allowBlank: true,\n    allowMulti: true,\n    allowLoop: true,\n    allowNode: true,\n    allowEdge: true,\n    allowPort: true,\n  }\n\n  notifyChange() {\n    this.props.onChange({\n      ...this.state,\n    })\n  }\n\n  onAllowTypeChanged = (type: string, flag: boolean) => {\n    const s = { [type]: flag } as any\n    this.setState(s, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Connecting Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 240 }}\n      >\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowBlank}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowBlank', e.target.checked)\n              }\n            >\n              AllowBlank\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowMulti}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowMulti', e.target.checked)\n              }\n            >\n              AllowMulti\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowLoop}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowLoop', e.target.checked)\n              }\n            >\n              AllowLoop\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowNode}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowNode', e.target.checked)\n              }\n            >\n              AllowNode\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowEdge}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowEdge', e.target.checked)\n              }\n            >\n              AllowEdge\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.allowPort}\n              onChange={(e) =>\n                this.onAllowTypeChanged('allowPort', e.target.checked)\n              }\n            >\n              AllowPort\n            </Checkbox>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  