  export default "import React from 'react'\nimport { Graph, Dom } from '@antv/x6'\nimport { Settings, State } from './settings'\nimport './index.less'\n\nGraph.registerNode(\n  'custom-group-node',\n  {\n    inherit: 'rect',\n    width: 80,\n    height: 40,\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n  },\n  true,\n)\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private embedPadding = 20\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      embedding: {\n        enabled: true,\n      },\n    })\n\n    const source = graph.addNode({\n      shape: 'custom-group-node',\n      x: 80,\n      y: 100,\n      width: 80,\n      height: 40,\n      label: 'Child',\n      zIndex: 2,\n    })\n\n    const target = graph.addNode({\n      shape: 'custom-group-node',\n      x: 280,\n      y: 80,\n      label: 'Child',\n      zIndex: 2,\n    })\n\n    const parent = graph.addNode({\n      shape: 'custom-group-node',\n      x: 40,\n      y: 40,\n      width: 360,\n      height: 160,\n      zIndex: 1,\n      label: 'Parent',\n    })\n\n    parent.addChild(source)\n    parent.addChild(target)\n\n    let ctrlPressed = false\n\n    graph.on('node:embedding', ({ e }: { e: Dom.MouseMoveEvent }) => {\n      ctrlPressed = e.metaKey || e.ctrlKey\n    })\n\n    graph.on('node:embedded', () => {\n      ctrlPressed = false\n    })\n\n    graph.on('node:change:size', ({ node, options }) => {\n      if (options.skipParentHandler) {\n        return\n      }\n\n      const children = node.getChildren()\n      if (children && children.length) {\n        node.prop('originSize', node.getSize())\n      }\n    })\n\n    graph.on('node:change:position', ({ node, options }) => {\n      if (options.skipParentHandler || ctrlPressed) {\n        return\n      }\n\n      const children = node.getChildren()\n      if (children && children.length) {\n        node.prop('originPosition', node.getPosition())\n      }\n\n      const parent = node.getParent()\n      if (parent && parent.isNode()) {\n        let originSize = parent.prop('originSize')\n        if (originSize == null) {\n          originSize = parent.getSize()\n          parent.prop('originSize', originSize)\n        }\n\n        let originPosition = parent.prop('originPosition')\n        if (originPosition == null) {\n          originPosition = parent.getPosition()\n          parent.prop('originPosition', originPosition)\n        }\n\n        let x = originPosition.x\n        let y = originPosition.y\n        let cornerX = originPosition.x + originSize.width\n        let cornerY = originPosition.y + originSize.height\n        let hasChange = false\n\n        const children = parent.getChildren()\n        if (children) {\n          children.forEach((child) => {\n            const bbox = child.getBBox().inflate(this.embedPadding)\n            const corner = bbox.getCorner()\n\n            if (bbox.x < x) {\n              x = bbox.x\n              hasChange = true\n            }\n\n            if (bbox.y < y) {\n              y = bbox.y\n              hasChange = true\n            }\n\n            if (corner.x > cornerX) {\n              cornerX = corner.x\n              hasChange = true\n            }\n\n            if (corner.y > cornerY) {\n              cornerY = corner.y\n              hasChange = true\n            }\n          })\n        }\n\n        if (hasChange) {\n          parent.prop(\n            {\n              position: { x, y },\n              size: { width: cornerX - x, height: cornerY - y },\n            },\n            // Note that we also pass a flag so that we know we shouldn't\n            // adjust the `originPosition` and `originSize` in our handlers.\n            { skipParentHandler: true },\n          )\n        }\n      }\n    })\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  onSettingsChanged = (state: State) => {\n    this.embedPadding = state.padding\n  }\n\n  render() {\n    return (\n      <div className=\"expand-shrink-app\">\n        <div className=\"app-side\">\n          <Settings onChange={this.onSettingsChanged} />\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  