  export default "import React from 'react'\nimport { Checkbox, Slider, Card, Row, Col } from 'antd'\nimport './index.less'\n\nexport interface Props {\n  onChange: (res: State) => void\n}\n\nexport interface State {\n  enabled: true\n  grid?: number\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    enabled: true,\n    grid: 15,\n  }\n\n  notifyChange() {\n    this.props.onChange({\n      ...this.state,\n    })\n  }\n\n  onEnableChanged = (e: any) => {\n    this.setState({ enabled: e.target.checked }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onGridChanged = (grid: number) => {\n    this.setState({ grid }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Rotating Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 320 }}\n      >\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.enabled}\n              onChange={this.onEnableChanged}\n            >\n              Enabled\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6}>grid</Col>\n          <Col span={14}>\n            <Slider\n              min={1}\n              max={180}\n              step={1}\n              value={this.state.grid}\n              onChange={this.onGridChanged}\n            />\n          </Col>\n          <Col span={2}>\n            <div className=\"slider-value\">{this.state.grid}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  