  export default "import React from 'react'\nimport { Radio, Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  refX: number\n  refY: number\n  xAlign?: string\n  yAlign?: string\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    refX: 0.5,\n    refY: 0.5,\n    xAlign: 'left',\n    yAlign: 'top',\n  }\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onRefXChanged = (refX: number) => {\n    this.setState({ refX }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onRefYChanged = (refY: number) => {\n    this.setState({ refY }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onXAlignChange = (e: any) => {\n    this.setState(\n      {\n        xAlign: e.target.value,\n      },\n      () => {\n        this.notifyChange()\n      },\n    )\n  }\n\n  onYAlignChange = (e: any) => {\n    this.setState(\n      {\n        yAlign: e.target.value,\n      },\n      () => {\n        this.notifyChange()\n      },\n    )\n  }\n\n  render() {\n    return (\n      <Card title=\"Attrs\" size=\"small\" bordered={false} style={{ width: 320 }}>\n        <Row align=\"middle\">\n          <Col span={5}>refX</Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={0.99}\n              step={0.01}\n              value={this.state.refX}\n              onChange={this.onRefXChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">\n              {(this.state.refX * 100).toFixed(0)}%\n            </div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5}>refY</Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={0.99}\n              step={0.01}\n              value={this.state.refY}\n              onChange={this.onRefYChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">\n              {(this.state.refY * 100).toFixed(0)}%\n            </div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5}>xAlign</Col>\n          <Col span={19}>\n            <Radio.Group\n              onChange={this.onXAlignChange}\n              value={this.state.xAlign}\n            >\n              <Radio value={'left'}>Left</Radio>\n              <Radio value={'middle'}>Middle</Radio>\n              <Radio value={'right'}>Right</Radio>\n            </Radio.Group>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5}>yAlign</Col>\n          <Col span={19}>\n            <Radio.Group\n              onChange={this.onYAlignChange}\n              value={this.state.yAlign}\n            >\n              <Radio value={'top'}>Top</Radio>\n              <Radio value={'middle'}>Middle</Radio>\n              <Radio value={'bottom'}>Bottom</Radio>\n            </Radio.Group>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  