  export default "import React from 'react'\nimport { Graph, Path, Point } from '@antv/x6'\nimport './index.less'\n\nexport interface WobbleArgs {\n  spread?: number\n  raw?: boolean\n}\n\nGraph.registerConnector(\n  'wobble',\n  (sourcePoint, targetPoint, vertices, args: WobbleArgs) => {\n    const spread = args.spread || 20\n    const points = [...vertices, targetPoint].map((p) => Point.create(p))\n    let prev = Point.create(sourcePoint)\n    const path = new Path()\n    path.appendSegment(Path.createSegment('M', prev))\n\n    for (let i = 0, n = points.length; i < n; i += 1) {\n      const next = points[i]\n      const distance = prev.distance(next)\n      let d = spread\n\n      while (d < distance) {\n        const current = prev.clone().move(next, -d)\n        current.translate(\n          Math.floor(7 * Math.random()) - 3,\n          Math.floor(7 * Math.random()) - 3,\n        )\n        path.appendSegment(Path.createSegment('L', current))\n        d += spread\n      }\n\n      path.appendSegment(Path.createSegment('L', next))\n      prev = next\n    }\n\n    return path\n  },\n  true,\n)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const rect1 = graph.addNode({\n      x: 30,\n      y: 30,\n      width: 100,\n      height: 40,\n      label: 'hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const rect2 = graph.addNode({\n      x: 300,\n      y: 240,\n      width: 100,\n      height: 40,\n      label: 'world',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    graph.addEdge({\n      source: rect1,\n      target: rect2,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n      vertices: [\n        { x: 100, y: 200 },\n        { x: 300, y: 120 },\n      ],\n      connector: {\n        name: 'wobble',\n        args: {\n          spread: 16,\n        },\n      },\n    })\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"connector-wobble-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  