  export default "import React from 'react'\nimport { Graph, Node, Color } from '@antv/x6'\nimport { Button } from 'antd'\nimport './index.less'\n\nGraph.registerNode(\n  'custom-node-with-port',\n  {\n    inherit: 'rect',\n    width: 100,\n    height: 40,\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n    ports: {\n      groups: {\n        top: {\n          position: 'top',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n          label: {\n            position: 'top',\n          },\n        },\n        bottom: {\n          position: 'bottom',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n          label: {\n            position: 'top',\n          },\n        },\n      },\n    },\n  },\n  true,\n)\n\nconst commands = [\n  {\n    key: 'addPort',\n    label: 'addPort',\n  },\n  {\n    key: 'removePort',\n    label: 'removePort',\n  },\n  {\n    key: 'updatePort',\n    label: 'updatePort',\n  },\n]\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private graph: Graph\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    graph.addNode({\n      id: '1',\n      shape: 'custom-node-with-port',\n      x: 150,\n      y: 100,\n      label: 'hello',\n    })\n\n    graph.centerContent()\n    this.graph = graph\n  }\n\n  change = (command: string) => {\n    const node = this.graph.getCellById('1') as Node\n    const ports = node.getPorts()\n    let color: string\n    switch (command) {\n      case 'addPort':\n        node.addPort({\n          group: 'top',\n          attrs: {\n            text: {\n              text: `${ports.length + 1}`,\n            },\n          },\n        })\n        break\n      case 'removePort':\n        if (ports.length) {\n          node.removePortAt(ports.length - 1)\n        }\n        break\n      case 'updatePort':\n        color = Color.random().toHex()\n        ports.forEach((port) => {\n          node.portProp(port.id!, 'attrs/circle/stroke', color)\n        })\n        break\n      default:\n        break\n    }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"dynamic-app\">\n        <div className=\"app-btns\">\n          <Button.Group>\n            {commands.map((item) => (\n              <Button onClick={() => this.change(item.key)} key={item.key}>\n                {item.label}\n              </Button>\n            ))}\n          </Button.Group>\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  