  export default "import React from 'react'\nimport { Radio, Switch, Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  position: string\n  strict: boolean\n  dx: number\n  dy: number\n  angle: number\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    position: 'left',\n    strict: false,\n    dx: 0,\n    dy: 0,\n    angle: 45,\n  }\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onDxChanged = (dx: number) => {\n    this.setState({ dx }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onDyChanged = (dy: number) => {\n    this.setState({ dy }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onAngleChanged = (angle: number) => {\n    this.setState({ angle }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onStrictChange = (strict: boolean) => {\n    this.setState({ strict }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onPositionChange = (e: any) => {\n    this.setState(\n      {\n        position: e.target.value,\n      },\n      () => {\n        this.notifyChange()\n      },\n    )\n  }\n\n  render() {\n    return (\n      <Card title=\"Args\" size=\"small\" bordered={false} style={{ width: 320 }}>\n        <Row align=\"middle\">\n          <Col span={6} style={{ textAlign: 'right', paddingRight: 16 }}>\n            position\n          </Col>\n          <Col span={12}>\n            <Radio.Group\n              value={this.state.position}\n              onChange={this.onPositionChange}\n            >\n              <Radio value={'left'}>left</Radio>\n              <Radio value={'right'}>right</Radio>\n              <Radio value={'top'}>top</Radio>\n              <Radio value={'bottom'}>bottom</Radio>\n            </Radio.Group>\n          </Col>\n        </Row>\n        <Row\n          align=\"middle\"\n          style={{ borderBottom: '1px solid #f0f0f0', paddingBottom: 24 }}\n        >\n          <Col span={6} style={{ textAlign: 'right', paddingRight: 16 }}>\n            strict\n          </Col>\n          <Col span={14}>\n            <Switch\n              checked={this.state.strict}\n              onChange={this.onStrictChange}\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6} style={{ textAlign: 'right', paddingRight: 16 }}>\n            dx\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={-10}\n              max={10}\n              step={1}\n              value={this.state.dx}\n              onChange={this.onDxChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.dx}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6} style={{ textAlign: 'right', paddingRight: 16 }}>\n            dy\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={-10}\n              max={10}\n              step={1}\n              value={this.state.dy}\n              onChange={this.onDyChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.dy}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6} style={{ textAlign: 'right', paddingRight: 16 }}>\n            angle\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={360}\n              step={1}\n              value={this.state.angle}\n              onChange={this.onAngleChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.angle}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  