  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport './index.less'\n\nGraph.registerNode(\n  'custom-node-with-port',\n  {\n    inherit: 'rect',\n    width: 100,\n    height: 40,\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n    ports: {\n      groups: {\n        top: {\n          position: 'top',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n        },\n        bottom: {\n          position: 'bottom',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n        },\n      },\n    },\n  },\n  true,\n)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      connecting: {\n        allowNode: false,\n        allowBlank: false,\n        highlight: true,\n        createEdge() {\n          return this.createEdge({\n            attrs: {\n              line: {\n                stroke: '#8f8f8f',\n                strokeWidth: 1,\n              },\n            },\n          })\n        },\n        validateMagnet({ magnet }) {\n          // 节点上方的连接桩无法创建连线\n          return magnet.getAttribute('port-group') !== 'top'\n        },\n        validateConnection({\n          sourceCell,\n          targetCell,\n          sourceMagnet,\n          targetMagnet,\n        }) {\n          // 不能连接自身\n          if (sourceCell === targetCell) {\n            return false\n          }\n\n          // 只能从 bottom 连接桩开始连接，连接到 top 连接桩\n          if (\n            !sourceMagnet ||\n            sourceMagnet.getAttribute('port-group') === 'top'\n          ) {\n            return false\n          }\n          if (\n            !targetMagnet ||\n            targetMagnet.getAttribute('port-group') !== 'top'\n          ) {\n            return false\n          }\n\n          // 不能重复连线\n          const edges = this.getEdges()\n          const portId = targetMagnet.getAttribute('port')\n          if (edges.find((edge) => edge.getTargetPortId() === portId)) {\n            return false\n          }\n\n          return true\n        },\n      },\n      highlighting: {\n        // 连接桩可以被连接时在连接桩外围围渲染一个包围框\n        magnetAvailable: {\n          name: 'stroke',\n          args: {\n            attrs: {\n              fill: '#fff',\n              stroke: '#A4DEB1',\n              strokeWidth: 4,\n            },\n          },\n        },\n        // 连接桩吸附连线时在连接桩外围围渲染一个包围框\n        magnetAdsorbed: {\n          name: 'stroke',\n          args: {\n            attrs: {\n              fill: '#fff',\n              stroke: '#31d0c6',\n              strokeWidth: 4,\n            },\n          },\n        },\n      },\n    })\n\n    graph.addNode({\n      shape: 'custom-node-with-port',\n      x: 40,\n      y: 40,\n      label: 'hello',\n      ports: {\n        items: [\n          {\n            id: 'port_1',\n            group: 'top',\n          },\n          {\n            id: 'port_2',\n            group: 'top',\n          },\n          {\n            id: 'port_3',\n            group: 'bottom',\n          },\n          {\n            id: 'port_4',\n            group: 'bottom',\n          },\n        ],\n      },\n    })\n\n    graph.addNode({\n      shape: 'custom-node-with-port',\n      x: 160,\n      y: 180,\n      label: 'world',\n      ports: {\n        items: [\n          {\n            id: 'port_5',\n            group: 'top',\n          },\n          {\n            id: 'port_6',\n            group: 'top',\n          },\n          {\n            id: 'port_7',\n            group: 'bottom',\n          },\n          {\n            id: 'port_8',\n            group: 'bottom',\n          },\n        ],\n      },\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"validate-app \">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  