  export default "/* eslint-disable jsx-a11y/no-static-element-interactions */\nimport React from 'react'\nimport { Graph } from '@antv/x6'\nimport { Dnd } from '@antv/x6-plugin-dnd'\nimport { Snapline } from '@antv/x6-plugin-snapline'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private graph: Graph\n  private container: HTMLDivElement\n  private dndContainer: HTMLDivElement\n  private dnd: Dnd\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      mousewheel: {\n        enabled: true,\n        modifiers: ['ctrl', 'meta'],\n      },\n    })\n\n    graph.use(\n      new Snapline({\n        enabled: true,\n        sharp: true,\n      }),\n    )\n\n    const source = graph.addNode({\n      x: 130,\n      y: 30,\n      width: 100,\n      height: 40,\n      label: 'Hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const target = graph.addNode({\n      x: 180,\n      y: 160,\n      width: 100,\n      height: 40,\n      label: 'World',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n    graph.centerContent()\n\n    this.dnd = new Dnd({\n      target: graph,\n      scaled: false,\n      dndContainer: this.dndContainer,\n    })\n    this.graph = graph\n  }\n\n  startDrag = (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => {\n    const target = e.currentTarget\n    const type = target.getAttribute('data-type')\n    const node =\n      type === 'rect'\n        ? this.graph.createNode({\n            width: 100,\n            height: 40,\n            label: 'Rect',\n            attrs: {\n              body: {\n                stroke: '#8f8f8f',\n                strokeWidth: 1,\n                fill: '#fff',\n                rx: 6,\n                ry: 6,\n              },\n            },\n          })\n        : this.graph.createNode({\n            width: 60,\n            height: 60,\n            shape: 'circle',\n            label: 'Circle',\n            attrs: {\n              body: {\n                stroke: '#8f8f8f',\n                strokeWidth: 1,\n                fill: '#fff',\n              },\n            },\n          })\n\n    this.dnd.start(node, e.nativeEvent as any)\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  dndContainerRef = (container: HTMLDivElement) => {\n    this.dndContainer = container\n  }\n\n  render() {\n    return (\n      <div className=\"dnd-app\">\n        <div className=\"dnd-wrap\" ref={this.dndContainerRef}>\n          <div\n            data-type=\"rect\"\n            className=\"dnd-rect\"\n            onMouseDown={this.startDrag}\n          >\n            Rect\n          </div>\n          <div\n            data-type=\"circle\"\n            className=\"dnd-circle\"\n            onMouseDown={this.startDrag}\n          >\n            Circle\n          </div>\n        </div>\n\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  