  export default "import React from 'react'\nimport { Graph, Point } from '@antv/x6'\nimport './index.less'\n\nGraph.registerRouter(\n  'random',\n  (vertices, args, view) => {\n    const BOUNCES = args.bounces || 20\n    const points = vertices.map((p) => Point.create(p))\n\n    for (let i = 0; i < BOUNCES; i += 1) {\n      const sourceCorner = view.sourceBBox.getCenter()\n      const targetCorner = view.targetBBox.getCenter()\n      const randomPoint = Point.random(\n        sourceCorner.x,\n        targetCorner.x,\n        sourceCorner.y,\n        targetCorner.y,\n      )\n      points.push(randomPoint)\n    }\n\n    return points\n  },\n  true,\n)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const source = graph.addNode({\n      x: 30,\n      y: 30,\n      width: 100,\n      height: 40,\n      label: 'Source',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const target = graph.addNode(\n      source.clone().translate(300, 200).attr('label/text', 'Target'),\n    )\n\n    graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n      router: {\n        name: 'random',\n        args: {\n          bounces: 3,\n        },\n      },\n    })\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"random-router-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  