  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport { Group } from './shape'\nimport './index.less'\n\nGraph.registerNode(\n  'custom-group-node',\n  {\n    inherit: 'rect',\n    width: 100,\n    height: 40,\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n  },\n  true,\n)\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const createGroup = (\n      id: string,\n      x: number,\n      y: number,\n      width: number,\n      height: number,\n      fill: string,\n    ) => {\n      const group = new Group({\n        id,\n        x,\n        y,\n        width,\n        height,\n        attrs: {\n          body: { fill },\n          label: { text: id },\n        },\n      })\n      graph.addNode(group)\n      return group\n    }\n\n    const createNode = (\n      id: string,\n      x: number,\n      y: number,\n      width: number,\n      height: number,\n    ) => {\n      return graph.addNode({\n        shape: 'custom-group-node',\n        id,\n        x,\n        y,\n        width,\n        height,\n        label: id,\n      })\n    }\n\n    const createEdge = (\n      id: string,\n      source: string,\n      target: string,\n      vertices?: { x: number; y: number }[],\n    ) => {\n      return graph.addEdge({\n        id,\n        source,\n        target,\n        vertices,\n        label: id,\n        attrs: {\n          line: {\n            stroke: '#8f8f8f',\n            strokeWidth: 1,\n          },\n        },\n      })\n    }\n\n    const a = createGroup('a', 100, 40, 480, 280, '#91d5ff')\n    const aa = createGroup('aa', 180, 100, 160, 140, '#47C769')\n    const aaa = createGroup('aaa', 200, 160, 120, 40, '#0491e4')\n    const b = createNode('b', 450, 200, 50, 50)\n\n    a.addChild(aa)\n    aa.addChild(aaa)\n    a.addChild(b)\n\n    createNode('c', 680, 80, 50, 50)\n\n    createEdge('edge1', 'aa', 'b')\n    createEdge('edge3', 'b', 'c')\n    aa.addChild(\n      createEdge('edge2', 'aa', 'aaa', [\n        { x: 60, y: 140 },\n        { x: 60, y: 220 },\n      ]),\n    )\n\n    graph.on('node:collapse', ({ node }: { node: Group }) => {\n      node.toggleCollapse()\n      const collapsed = node.isCollapsed()\n      const collapse = (parent: Group) => {\n        const cells = parent.getChildren()\n        if (cells) {\n          cells.forEach((cell) => {\n            if (collapsed) {\n              cell.hide()\n            } else {\n              cell.show()\n            }\n\n            if (cell instanceof Group) {\n              if (!cell.isCollapsed()) {\n                collapse(cell)\n              }\n            }\n          })\n        }\n      }\n\n      collapse(node)\n    })\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"collapsable-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  