  export default "import { useGraphStore, useClipboard } from '@antv/xflow'\nimport React, { useEffect, useState, useCallback } from 'react'\nimport { Card, Row, Col, Slider, Checkbox, Button, Badge } from 'antd'\n\nexport const Setting = (props) => {\n  const initData = useGraphStore((state) => state.initData)\n\n  const setInitData = useCallback(() => {\n    initData({\n      nodes: [\n        {\n          id: '1',\n          x: 32,\n          y: 32,\n          width: 100,\n          height: 40,\n          label: 'Hello',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n              rx: 6,\n              ry: 6,\n            },\n          },\n        },\n        {\n          id: '2',\n          shape: 'circle',\n          x: 160,\n          y: 180,\n          width: 60,\n          height: 60,\n          label: 'World',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n            },\n          },\n        },\n      ],\n      edges: [\n        {\n          source: '1',\n          target: '2',\n          attrs: {\n            line: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n            },\n          },\n        },\n      ],\n    })\n  }, [initData])\n\n  useEffect(() => {\n    setInitData()\n  }, [setInitData])\n  const [offset, setOffset] = useState(30)\n  const nodes = useGraphStore((state) => state.nodes)\n  const { copy, paste } = useClipboard()\n\n  const onCopy = () => {\n    const selected = nodes.filter((node) => node.selected)\n    const ids: string[] = selected.map((node) => node.id || '')\n    copy(ids)\n  }\n\n  const onPaste = () => {\n    paste({ offset })\n  }\n\n  return (\n    <div>\n      <Card title=\"Card title\" bordered={false}>\n        <Row align=\"middle\">\n          <Col span={10}>Paste Offset</Col>\n          <Col span={2} offset={1}>\n            <Badge\n              overflowCount={999}\n              count={offset}\n              showZero\n              color=\"#faad14\"\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Slider\n              min={1}\n              max={80}\n              step={1}\n              value={offset}\n              onChange={(value) => setOffset(value)}\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={props.value}\n              onChange={(e) => props.setLocalStorage(e.target.checked)}\n            >\n              useLocalStorage\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={10}>\n            <Button type=\"primary\" onClick={onCopy}>\n              Copy Cell\n            </Button>\n          </Col>\n          <Col span={10} offset={4}>\n            <Button onClick={onPaste}>Paste Cell</Button>\n          </Col>\n        </Row>\n      </Card>\n    </div>\n  )\n}\n";;
  