  export default "import { useEffect, useCallback } from 'react'\nimport { useGraphStore, useClipboard, useKeyboard } from '@antv/xflow'\n\nexport const Header = () => {\n  const { copy, paste } = useClipboard()\n\n  const addNodes = useGraphStore((state) => state.addNodes)\n  const addEdges = useGraphStore((state) => state.addEdges)\n  const nodes = useGraphStore((state) => state.nodes)\n\n  const setAddNodes = useCallback(() => {\n    addNodes([\n      {\n        id: 'source',\n        x: 32,\n        y: 32,\n        width: 100,\n        height: 40,\n        label: 'Hello',\n        attrs: {\n          body: {\n            stroke: '#8f8f8f',\n            strokeWidth: 1,\n            fill: '#fff',\n            rx: 6,\n            ry: 6,\n          },\n        },\n      },\n      {\n        id: 'target',\n        shape: 'circle',\n        x: 160,\n        y: 180,\n        width: 60,\n        height: 60,\n        label: 'World',\n        attrs: {\n          body: {\n            stroke: '#8f8f8f',\n            strokeWidth: 1,\n            fill: '#fff',\n          },\n        },\n      },\n    ])\n  }, [addNodes])\n\n  const setAddEdges = useCallback(() => {\n    addEdges([\n      {\n        source: 'source',\n        target: 'target',\n        attrs: {\n          line: {\n            stroke: '#8f8f8f',\n            strokeWidth: 1,\n          },\n        },\n      },\n    ])\n  }, [addEdges])\n\n  const onCopy = () => {\n    const selected = nodes.filter((node) => node.selected)\n    const ids: string[] = selected.map((node) => node.id || '')\n    copy(ids)\n  }\n\n  useKeyboard('ctrl+c', () => {\n    onCopy()\n  })\n\n  useKeyboard('ctrl+v', () => {\n    paste()\n  })\n\n  useEffect(() => {\n    setAddNodes()\n    setAddEdges()\n  }, [setAddEdges, setAddNodes])\n\n  return null\n}\n";;
  