  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport { Button } from 'antd'\nimport './index.less'\n\nconst data = {\n  nodes: [\n    {\n      id: 'node1',\n      shape: 'rect',\n      x: 40,\n      y: 40,\n      width: 100,\n      height: 40,\n      label: 'hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    },\n    {\n      id: 'node2',\n      shape: 'rect',\n      x: 160,\n      y: 180,\n      width: 100,\n      height: 40,\n      label: 'world',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    },\n  ],\n  edges: [\n    {\n      shape: 'edge',\n      source: 'node1',\n      target: 'node2',\n      label: 'x6',\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    },\n  ],\n}\n\nconst commands = [\n  {\n    key: 'zoomIn',\n    label: 'ZoomIn(0.2)',\n  },\n  {\n    key: 'zoomOut',\n    label: 'ZoomOut(-0.2)',\n  },\n  {\n    key: 'zoomTo',\n    label: 'ZoomTo(1)',\n  },\n  {\n    key: 'zoomToFit',\n    label: 'ZoomToFit',\n  },\n  {\n    key: 'centerContent',\n    label: 'CenterContent',\n  },\n]\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private graph: Graph\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      grid: {\n        visible: true,\n        type: 'doubleMesh',\n        args: [\n          {\n            color: '#eee', // 主网格线颜色\n            thickness: 1, // 主网格线宽度\n          },\n          {\n            color: '#ddd', // 次网格线颜色\n            thickness: 1, // 次网格线宽度\n            factor: 4, // 主次网格线间隔\n          },\n        ],\n      },\n      panning: true,\n      mousewheel: {\n        enabled: true,\n        modifiers: 'Ctrl',\n        maxScale: 4,\n        minScale: 0.2,\n      },\n    })\n\n    graph.fromJSON(data)\n    graph.centerContent()\n    this.graph = graph\n  }\n\n  transform = (command: string) => {\n    switch (command) {\n      case 'translate':\n        this.graph.translate(20, 20)\n        break\n      case 'zoomIn':\n        this.graph.zoom(0.2)\n        break\n      case 'zoomOut':\n        this.graph.zoom(-0.2)\n        break\n      case 'zoomTo':\n        this.graph.zoomTo(1)\n        break\n      case 'zoomToFit':\n        this.graph.zoomToFit()\n        break\n      case 'centerContent':\n        this.graph.centerContent()\n        break\n      default:\n        break\n    }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"transform-app\">\n        <div className=\"app-btns\">\n          <Button.Group>\n            {commands.map((item) => (\n              <Button onClick={() => this.transform(item.key)} key={item.key}>\n                {item.label}\n              </Button>\n            ))}\n          </Button.Group>\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  