  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport { Vertices } from '@antv/x6/es/registry/tool/vertices'\nimport './index.less'\n\nconst RedVertices = Vertices.define<Vertices.Options>({\n  name: 'red-vertices',\n  attrs: {\n    fill: 'red',\n  },\n})\n\nGraph.registerEdgeTool('red-vertices', RedVertices, true)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    graph.addEdge({\n      source: { x: 40, y: 40 },\n      target: { x: 380, y: 40 },\n      vertices: [\n        { x: 40, y: 80 },\n        { x: 200, y: 80 },\n        { x: 200, y: 40 },\n      ],\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          targetMarker: 'classic',\n        },\n      },\n      tools: ['red-vertices'],\n    })\n\n    const edge2 = graph.addEdge({\n      source: { x: 60, y: 140 },\n      target: { x: 380, y: 140 },\n      vertices: [\n        { x: 40, y: 180 },\n        { x: 200, y: 140 },\n        { x: 240, y: 180 },\n      ],\n      connector: 'smooth',\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          targetMarker: 'classic',\n        },\n      },\n    })\n\n    graph.on('edge:mouseenter', ({ cell }) => {\n      if (cell === edge2) {\n        cell.addTools([{ name: 'red-vertices' }])\n      }\n    })\n\n    graph.on('edge:mouseleave', ({ cell }) => {\n      if (cell === edge2) {\n        if (cell.hasTool('red-vertices')) {\n          cell.removeTool('red-vertices')\n        }\n      }\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"edge-tool-custom-vertices-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  