  export default "import React from 'react'\nimport { Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  scale: number\n  tx: number\n  ty: number\n}\n\nexport const defaults: State = {\n  scale: 1,\n  tx: 0,\n  ty: 0,\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = defaults\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onScaleChanged = (scale: number) => {\n    this.setState({ scale }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onTxChanged = (tx: number) => {\n    this.setState({ tx }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onTyChanged = (ty: number) => {\n    this.setState({ ty }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 320 }}\n      >\n        <Row align=\"middle\">\n          <Col span={7}>scale</Col>\n          <Col span={12}>\n            <Slider\n              min={0.1}\n              max={2}\n              step={0.1}\n              value={this.state.scale}\n              onChange={this.onScaleChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.scale}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={7}>translateX</Col>\n          <Col span={12}>\n            <Slider\n              min={-50}\n              max={50}\n              step={1}\n              value={this.state.tx}\n              onChange={this.onTxChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.tx}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={7}>translateY</Col>\n          <Col span={12}>\n            <Slider\n              min={-50}\n              max={50}\n              step={1}\n              value={this.state.ty}\n              onChange={this.onTyChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.ty}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  