  export default "import React from 'react'\nimport { Button, message } from 'antd'\nimport { Graph } from '@antv/x6'\nimport { Clipboard } from '@antv/x6-plugin-clipboard'\nimport { Selection } from '@antv/x6-plugin-selection'\nimport { Settings, State } from './settings'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private graph: Graph\n  private options: State\n\n  componentDidMount() {\n    this.graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    this.graph.use(\n      new Selection({\n        enabled: true,\n        showNodeSelectionBox: true,\n      }),\n    )\n\n    this.graph.use(\n      new Clipboard({\n        enabled: true,\n        useLocalStorage: true,\n      }),\n    )\n\n    this.graph.addNode({\n      x: 280,\n      y: 80,\n      width: 100,\n      height: 40,\n      label: 'Rect',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const source = this.graph.addNode({\n      x: 32,\n      y: 32,\n      width: 100,\n      height: 40,\n      label: 'Hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const target = this.graph.addNode({\n      shape: 'circle',\n      x: 180,\n      y: 160,\n      width: 60,\n      height: 60,\n      label: 'World',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n        },\n      },\n    })\n\n    this.graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n  }\n\n  onSettingsChanged = (options: State) => {\n    this.options = { ...options }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  onCopy = () => {\n    const cells = this.graph.getSelectedCells()\n    if (cells && cells.length) {\n      this.graph.copy(cells, this.options)\n      message.success('复制成功')\n    } else {\n      message.info('请先选中节点再复制')\n    }\n  }\n\n  onPaste = () => {\n    if (this.graph.isClipboardEmpty()) {\n      message.info('剪切板为空，不可粘贴')\n    } else {\n      const cells = this.graph.paste(this.options)\n      this.graph.cleanSelection()\n      this.graph.select(cells)\n      message.success('粘贴成功')\n    }\n  }\n\n  render() {\n    return (\n      <div className=\"clipboard-app\">\n        <div className=\"app-side\">\n          <Settings onChange={this.onSettingsChanged} />\n          <div className=\"app-btns\">\n            <Button onClick={this.onCopy} type=\"primary\">\n              Copy Selected Cells\n            </Button>\n            <Button onClick={this.onPaste} type=\"ghost\">\n              Paste\n            </Button>\n          </div>\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  