  export default "import React from 'react'\nimport { Graph, Color, NodeView } from '@antv/x6'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const source = graph.addNode({\n      x: 40,\n      y: 40,\n      width: 120,\n      height: 48,\n      label: 'source',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n      tools: [\n        {\n          name: 'button',\n          args: {\n            markup: [\n              {\n                tagName: 'circle',\n                selector: 'button',\n                attrs: {\n                  r: 14,\n                  stroke: '#fe854f',\n                  'stroke-width': 3,\n                  fill: 'white',\n                  cursor: 'pointer',\n                },\n              },\n              {\n                tagName: 'text',\n                textContent: 'Btn A',\n                selector: 'icon',\n                attrs: {\n                  fill: '#fe854f',\n                  'font-size': 8,\n                  'text-anchor': 'middle',\n                  'pointer-events': 'none',\n                  y: '0.3em',\n                },\n              },\n            ],\n            x: '100%',\n            y: '100%',\n            offset: { x: -18, y: -18 },\n            onClick({ view }: { view: NodeView }) {\n              const node = view.cell\n              const fill = Color.randomHex()\n              node.attr({\n                body: {\n                  fill,\n                },\n                label: {\n                  fill: Color.invert(fill, true),\n                },\n              })\n            },\n          },\n        },\n      ],\n    })\n\n    const target = graph.addNode({\n      x: 160,\n      y: 180,\n      width: 120,\n      height: 48,\n      label: 'target',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    graph.on('node:mouseenter', ({ node }) => {\n      if (node === target) {\n        node.addTools({\n          name: 'button',\n          args: {\n            markup: [\n              {\n                tagName: 'circle',\n                selector: 'button',\n                attrs: {\n                  r: 14,\n                  stroke: '#fe854f',\n                  'stroke-width': 3,\n                  fill: 'white',\n                  cursor: 'pointer',\n                },\n              },\n              {\n                tagName: 'text',\n                textContent: 'Btn B',\n                selector: 'icon',\n                attrs: {\n                  fill: '#fe854f',\n                  'font-size': 8,\n                  'text-anchor': 'middle',\n                  'pointer-events': 'none',\n                  y: '0.3em',\n                },\n              },\n            ],\n            x: 0,\n            y: 0,\n            offset: { x: 18, y: 18 },\n            onClick({ view }: { view: NodeView }) {\n              const node = view.cell\n              const offset = parseInt(\n                node.attr('body/strokeDashoffset') || '0',\n                10,\n              )\n              node.attr({\n                body: {\n                  stroke: Color.randomHex(),\n                  strokeDasharray: '5, 1',\n                  strokeDashoffset: offset + 20,\n                },\n              })\n            },\n          },\n        })\n      }\n    })\n\n    graph.on('node:mouseleave', ({ cell }) => {\n      if (cell === target) {\n        cell.removeTools()\n      }\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"button-tool-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  