  export default "import { useGraphStore } from '@antv/xflow'\nimport React, { useEffect, useCallback } from 'react'\nimport { Card, Row, Col, Segmented, Select } from 'antd'\n\nexport const Setting = ({ setOptions }) => {\n  const initData = useGraphStore((state) => state.initData)\n\n  const setInitData = useCallback(() => {\n    initData({\n      nodes: [\n        {\n          id: '1',\n          x: 32,\n          y: 32,\n          width: 100,\n          height: 40,\n          label: 'Hello',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n              rx: 6,\n              ry: 6,\n            },\n          },\n        },\n        {\n          id: '2',\n          shape: 'circle',\n          x: 160,\n          y: 180,\n          width: 60,\n          height: 60,\n          label: 'World',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n            },\n          },\n        },\n      ],\n      edges: [\n        {\n          source: '1',\n          target: '2',\n          attrs: {\n            line: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n            },\n          },\n        },\n      ],\n    })\n  }, [initData])\n\n  useEffect(() => {\n    setInitData()\n  }, [setInitData])\n\n  const controlItems = [\n    'zoomOut',\n    'zoomTo',\n    'zoomIn',\n    'zoomToFit',\n    'zoomToOrigin',\n  ]\n  const selectOptions = controlItems.map((item) => ({\n    label: item,\n    value: item,\n  }))\n\n  return (\n    <div>\n      <Card title=\"Control 配置\" bordered={false}>\n        <Row align=\"middle\">\n          <Col span={20}>\n            <Segmented\n              options={[\n                {\n                  label: '水平展示',\n                  value: 'horizontal',\n                },\n                {\n                  label: '垂直展示',\n                  value: 'vertical',\n                },\n              ]}\n              block\n              onChange={(value) =>\n                setOptions((prev) => ({ ...prev, direction: value }))\n              }\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">Tooltip</Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Segmented\n              options={['top', 'right', 'left', 'bottom']}\n              onChange={(value) =>\n                setOptions((prev) => ({ ...prev, placement: value }))\n              }\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6}>Options </Col>\n          <Col span={14}>\n            <Select\n              mode=\"multiple\"\n              allowClear\n              style={{ width: '100%' }}\n              defaultValue={[\n                'zoomOut',\n                'zoomTo',\n                'zoomIn',\n                'zoomToFit',\n                'zoomToOrigin',\n              ]}\n              placeholder=\"Please select\"\n              onChange={(value) =>\n                setOptions((prev) => ({ ...prev, items: value }))\n              }\n              options={selectOptions}\n            />\n          </Col>\n        </Row>\n      </Card>\n    </div>\n  )\n}\n";;
  