  export default "import { useGraphStore, useGraphEvent } from '@antv/xflow'\nimport { useCallback, useEffect } from 'react'\n\nexport const InitNode = () => {\n  const addNodes = useGraphStore((state) => state.addNodes)\n  const updateNode = useGraphStore((state) => state.updateNode)\n\n  useGraphEvent('node:click', ({ node }) => {\n    const { id } = node\n    const randomColor = Math.floor(Math.random() * 16777215).toString(16)\n    const fillColor = `#${randomColor}`\n    updateNode(id, {\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: fillColor,\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n  })\n\n  const addNodeInit = useCallback(() => {\n    addNodes([\n      {\n        id: '3',\n        shape: 'rect',\n        x: 200,\n        y: 200,\n        width: 100,\n        height: 40,\n        attrs: {\n          body: {\n            stroke: '#8f8f8f',\n            strokeWidth: 1,\n            fill: '#fff',\n            rx: 6,\n            ry: 6,\n          },\n        },\n        label: 'added',\n      },\n    ])\n  }, [addNodes])\n\n  useEffect(() => {\n    addNodeInit()\n  }, [addNodeInit])\n\n  return null\n}\n";;
  