  export default "import React from 'react'\nimport { Radio, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  position: string\n  dx: number\n  dy: number\n  angle: number\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    position: 'left',\n    dx: 0,\n    dy: 0,\n    angle: 45,\n  }\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onDxChanged = (dx: number) => {\n    this.setState({ dx }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onDyChanged = (dy: number) => {\n    this.setState({ dy }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onAngleChanged = (angle: number) => {\n    this.setState({ angle }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onPositionChange = (e: any) => {\n    this.setState(\n      {\n        position: e.target.value,\n      },\n      () => {\n        this.notifyChange()\n      },\n    )\n  }\n\n  render() {\n    const radioStyle = {\n      display: 'block',\n      height: '36px',\n      lineHeight: '36px',\n    }\n\n    return (\n      <Card\n        title=\"Port Label Position\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 240 }}\n      >\n        <Row align=\"middle\" justify=\"center\">\n          <Col>\n            <Radio.Group\n              value={this.state.position}\n              onChange={this.onPositionChange}\n            >\n              <Radio style={radioStyle} value={'left'}>\n                left\n              </Radio>\n              <Radio style={radioStyle} value={'right'}>\n                right\n              </Radio>\n              <Radio style={radioStyle} value={'top'}>\n                top\n              </Radio>\n              <Radio style={radioStyle} value={'bottom'}>\n                bottom\n              </Radio>\n            </Radio.Group>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  