  export default "import React from 'react'\nimport { Graph, Color } from '@antv/x6'\nimport { Button } from '@antv/x6/es/registry/tool/button'\nimport './index.less'\n\nconst MyButton = Button.define<Button.Options>({\n  markup: [\n    {\n      tagName: 'rect',\n      selector: 'button',\n      attrs: {\n        width: 40,\n        height: 20,\n        rx: 4,\n        ry: 4,\n        fill: 'white',\n        stroke: '#fe854f',\n        'stroke-width': 2,\n        cursor: 'pointer',\n      },\n    },\n    {\n      tagName: 'text',\n      selector: 'text',\n      textContent: 'btn',\n      attrs: {\n        fill: '#fe854f',\n        'font-size': 10,\n        'text-anchor': 'middle',\n        'pointer-events': 'none',\n        x: 20,\n        y: 13,\n      },\n    },\n  ],\n  onClick({ view }: any) {\n    const node = view.cell\n    const fill = Color.randomHex()\n    node.attr({\n      body: {\n        fill,\n      },\n      label: {\n        fill: Color.invert(fill, true),\n      },\n    })\n  },\n})\n\nGraph.registerNodeTool('my-btn', MyButton, true)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const source = graph.addNode({\n      x: 40,\n      y: 40,\n      width: 140,\n      height: 48,\n      label: 'source',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n      tools: [\n        {\n          name: 'my-btn',\n          args: {\n            x: '100%',\n            y: '100%',\n            offset: { x: -44, y: -24 },\n          },\n        },\n      ],\n    })\n\n    const target = graph.addNode({\n      x: 160,\n      y: 160,\n      width: 140,\n      height: 48,\n      label: 'target',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"custom-button-tool-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  