  export default "import React from 'react'\nimport { Checkbox, Slider, Card, Row, Col } from 'antd'\nimport './index.less'\n\nexport interface Props {\n  onChange: (res: State) => void\n}\n\nexport interface State {\n  offset: number\n  useLocalStorage: boolean\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    offset: 30,\n    useLocalStorage: true,\n  }\n\n  componentDidMount() {\n    this.notifyChange()\n  }\n\n  notifyChange() {\n    this.props.onChange({\n      ...this.state,\n    })\n  }\n\n  onUseLocalStorageChanged = (e: any) => {\n    this.setState({ useLocalStorage: e.target.checked }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onOffsetChanged = (offset: number) => {\n    this.setState({ offset }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Clipboard Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 320 }}\n      >\n        <Row align=\"middle\">\n          <Col span={8}>Paste Offset</Col>\n          <Col span={2} offset={1}>\n            <div className=\"slider-value\">{this.state.offset}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Slider\n              min={10}\n              max={80}\n              step={1}\n              value={this.state.offset}\n              onChange={this.onOffsetChanged}\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              checked={this.state.useLocalStorage}\n              onChange={this.onUseLocalStorageChanged}\n            >\n              Use LocalStorage\n            </Checkbox>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  