  export default "import React from 'react'\nimport { Button } from 'antd'\nimport { Graph } from '@antv/x6'\nimport { Scroller } from '@antv/x6-plugin-scroller'\nimport { Settings, State } from './settings'\nimport './index.less'\n\nconst data = {\n  hello: {\n    id: 'hello',\n    x: 32,\n    y: 32,\n    width: 100,\n    height: 40,\n    label: 'Hello',\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n  },\n  world: {\n    id: 'world',\n    shape: 'circle',\n    x: 160,\n    y: 180,\n    width: 60,\n    height: 60,\n    label: 'World',\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n      },\n    },\n  },\n  rect: {\n    id: 'rect',\n    x: -60,\n    y: 100,\n    width: 100,\n    height: 40,\n    label: 'Rect',\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n  },\n}\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private graph: Graph\n\n  componentDidMount() {\n    this.renderGraph()\n  }\n\n  renderGraph(options: State | null = null) {\n    if (this.graph) {\n      this.graph.dispose()\n    }\n\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n    graph.use(\n      new Scroller({\n        enabled: true,\n        pageVisible: true,\n        pageBreak: true,\n        pannable: true,\n        ...options,\n      }),\n    )\n\n    graph.fromJSON({ nodes: Object.keys(data).map((key) => data[key]) })\n\n    graph.on('node:change:position', ({ node, current }) => {\n      const item = data[node.id]\n      item.x = current!.x\n      item.y = current!.y\n    })\n\n    graph.centerContent()\n    this.graph = graph\n  }\n\n  onSettingsChanged = (options: State) => {\n    this.renderGraph(options)\n  }\n\n  onCenter = () => {\n    this.graph.center()\n  }\n\n  onCenterContent = () => {\n    this.graph.centerContent()\n  }\n\n  onCenterCircle = () => {\n    const circle = this.graph.getCellById('world')\n    if (circle) {\n      this.graph.centerCell(circle)\n    }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"scroller-app\">\n        <div className=\"app-side\">\n          <Settings onChange={this.onSettingsChanged} />\n        </div>\n        <div className=\"app-main\">\n          <div className=\"app-btns\">\n            <Button onClick={this.onCenter}>Center Graph</Button>\n            <Button onClick={this.onCenterContent}>Center Whole Content</Button>\n            <Button onClick={this.onCenterCircle}>Center The Circle</Button>\n          </div>\n          <div className=\"app-content\" ref={this.refContainer} />\n        </div>\n      </div>\n    )\n  }\n}\n";;
  