  export default "import React from 'react'\nimport { Input, Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  color: string\n  angle: number\n}\n\nexport const defaults: State = {\n  color: '#4943a3',\n  angle: 0,\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = defaults\n\n  notifyChange() {\n    this.props.onChange({\n      ...this.state,\n    })\n  }\n\n  onColorChanged = (e: any) => {\n    this.setState({ color: e.target.value }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onAngleChanged = (dx: number) => {\n    this.setState({ angle: dx }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 320 }}\n      >\n        <Row align=\"middle\">\n          <Col span={6}>fill</Col>\n          <Col span={14}>\n            <Input\n              type=\"color\"\n              value={this.state.color}\n              style={{ width: '100%' }}\n              onChange={this.onColorChanged}\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6}>angle</Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={360}\n              step={1}\n              value={this.state.angle}\n              onChange={this.onAngleChanged}\n            />\n          </Col>\n          <Col span={2}>\n            <div className=\"slider-value\">{this.state.angle.toFixed(2)}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  