  export default "import React from 'react'\nimport { Graph, Edge } from '@antv/x6'\nimport { Settings, State } from './settings'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private edge: Edge\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      interacting: false,\n    })\n\n    const rect = graph.addEdge({\n      source: { x: 40, y: 80 },\n      target: { x: 360, y: 80 },\n      vertices: [\n        { x: 120, y: 120 },\n        { x: 200, y: 40 },\n        { x: 280, y: 120 },\n      ],\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    const edge = graph.addEdge({\n      source: { x: 100, y: 100 },\n      target: { cell: rect.id },\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          targetMarker: 'classic',\n        },\n      },\n    })\n\n    function animate() {\n      edge.transition('source', 9.36 / 60, {\n        duration: 5000,\n        interp: (start, startTime) => {\n          const corr = startTime * (2 * Math.PI) - Math.PI / 2\n          const origin = { x: 200, y: 100 }\n          const radius = 140\n          return function (t) {\n            return {\n              x: origin.x + radius * Math.cos(t * 2 * Math.PI + corr),\n              y: origin.y + radius * Math.sin(t * 2 * Math.PI + corr),\n            }\n          }\n        },\n      })\n    }\n\n    animate()\n\n    edge.on('transition:complete', animate)\n\n    this.edge = edge\n  }\n\n  onAttrsChanged = ({ type, value }: State) => {\n    const anchor =\n      type === 'ratio' || type === 'length'\n        ? {\n            name: type,\n            args: {\n              [type]: value,\n            },\n          }\n        : { name: type }\n    this.edge.prop('target/anchor', anchor)\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"edge-anchor-app\">\n        <div className=\"app-side\">\n          <Settings onChange={this.onAttrsChanged} />\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  