  export default "import { useGraphStore } from '@antv/xflow'\nimport React, { useEffect, useCallback } from 'react'\nimport { Card, Row, Col, Slider, Checkbox, Badge } from 'antd'\n\nexport const Setting = ({ setOptions, options }) => {\n  const initData = useGraphStore((state) => state.initData)\n  const setInitData = useCallback(() => {\n    initData({\n      nodes: [\n        {\n          id: '1',\n          x: 32,\n          y: 32,\n          width: 100,\n          height: 40,\n          label: 'Hello',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n              rx: 6,\n              ry: 6,\n            },\n          },\n        },\n        {\n          id: '2',\n          shape: 'circle',\n          x: 160,\n          y: 180,\n          width: 60,\n          height: 60,\n          label: 'World',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n            },\n          },\n        },\n        {\n          id: '3',\n          x: 200,\n          y: 100,\n          width: 100,\n          height: 40,\n          label: 'Drag Me',\n          attrs: {\n            body: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n              fill: '#fff',\n              rx: 6,\n              ry: 6,\n            },\n          },\n        },\n      ],\n      edges: [\n        {\n          source: '1',\n          target: '2',\n          attrs: {\n            line: {\n              stroke: '#8f8f8f',\n              strokeWidth: 1,\n            },\n          },\n        },\n      ],\n    })\n  }, [initData])\n  useEffect(() => {\n    setInitData()\n  }, [setInitData])\n\n  return (\n    <div>\n      <Card title=\"Snapline 配置\" bordered={false}>\n        <Row align=\"middle\">\n          <Col span={6}>Tolerance</Col>\n          <Col span={2} offset={1}>\n            <Badge count={options.tolerance} showZero color=\"#faad14\" />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Slider\n              min={1}\n              max={30}\n              step={1}\n              value={options.tolerance}\n              onChange={(value) =>\n                setOptions((prev) => ({ ...prev, tolerance: value }))\n              }\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              onChange={(e) =>\n                setOptions((prev) => ({ ...prev, sharp: e.target.checked }))\n              }\n            >\n              Sharp Line\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              onChange={(e) =>\n                setOptions((prev) => ({ ...prev, resizing: e.target.checked }))\n              }\n            >\n              Snap on Resizing\n            </Checkbox>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={24}>\n            <Checkbox\n              onChange={(e) =>\n                setOptions((prev) => ({\n                  ...prev,\n                  filter: e.target.checked ? ['circle'] : undefined,\n                }))\n              }\n            >\n              Add Filter(only circle)\n            </Checkbox>\n          </Col>\n        </Row>\n      </Card>\n    </div>\n  )\n}\n";;
  