  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport './index.less'\n\nGraph.registerNode(\n  'custom-node-with-port',\n  {\n    inherit: 'rect',\n    width: 100,\n    height: 40,\n    attrs: {\n      body: {\n        stroke: '#8f8f8f',\n        strokeWidth: 1,\n        fill: '#fff',\n        rx: 6,\n        ry: 6,\n      },\n    },\n    ports: {\n      groups: {\n        in: {\n          position: 'top',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n        },\n        out: {\n          position: 'bottom',\n          attrs: {\n            circle: {\n              magnet: true,\n              stroke: '#8f8f8f',\n              r: 5,\n            },\n          },\n        },\n      },\n    },\n  },\n  true,\n)\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const magnetAvailabilityHighlighter = {\n      name: 'stroke',\n      args: {\n        padding: 3,\n        attrs: {\n          strokeWidth: 3,\n          stroke: '#52c41a',\n        },\n      },\n    }\n\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      highlighting: {\n        magnetAvailable: magnetAvailabilityHighlighter,\n      },\n      connecting: {\n        snap: true,\n        allowBlank: false,\n        allowLoop: false,\n        allowNode: false,\n        highlight: true,\n\n        createEdge() {\n          return this.createEdge({\n            attrs: {\n              line: {\n                stroke: '#8f8f8f',\n                strokeWidth: 1,\n              },\n            },\n          })\n        },\n\n        validateMagnet({ magnet }) {\n          return magnet.getAttribute('port-group') !== 'in'\n        },\n\n        validateConnection({ sourceMagnet, targetMagnet }) {\n          // 只能从输出链接桩创建连接\n          if (\n            !sourceMagnet ||\n            sourceMagnet.getAttribute('port-group') === 'in'\n          ) {\n            return false\n          }\n\n          // 只能连接到输入链接桩\n          if (\n            !targetMagnet ||\n            targetMagnet.getAttribute('port-group') !== 'in'\n          ) {\n            return false\n          }\n\n          return true\n        },\n      },\n    })\n\n    const source = graph.addNode({\n      shape: 'custom-node-with-port',\n      x: 40,\n      y: 40,\n      width: 100,\n      height: 40,\n      label: 'source',\n      ports: [\n        { id: 'in-1', group: 'in' },\n        { id: 'in-2', group: 'in' },\n        { id: 'out-1', group: 'out' },\n        { id: 'out-2', group: 'out' },\n      ],\n    })\n\n    const target = graph.addNode({\n      shape: 'custom-node-with-port',\n      x: 140,\n      y: 240,\n      width: 100,\n      height: 40,\n      label: 'target',\n      ports: [\n        { id: 'in-1', group: 'in' },\n        { id: 'in-2', group: 'in' },\n        { id: 'out-1', group: 'out' },\n        { id: 'out-2', group: 'out' },\n      ],\n    })\n\n    graph.addNode({\n      shape: 'custom-node-with-port',\n      x: 320,\n      y: 120,\n      width: 100,\n      height: 40,\n      label: 'hello',\n      ports: [\n        { id: 'in-1', group: 'in' },\n        { id: 'in-2', group: 'in' },\n        { id: 'out-1', group: 'out' },\n        { id: 'out-2', group: 'out' },\n      ],\n    })\n\n    graph.addEdge({\n      source: { cell: source.id, port: 'out-2' },\n      target: { cell: target.id, port: 'in-1' },\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    graph.on('edge:mouseenter', ({ cell }) => {\n      cell.addTools([\n        {\n          name: 'source-arrowhead',\n        },\n        {\n          name: 'target-arrowhead',\n          args: {\n            attrs: {\n              fill: 'red',\n            },\n          },\n        },\n      ])\n    })\n\n    graph.on('edge:mouseleave', ({ cell }) => {\n      cell.removeTools()\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"edge-tool-arrowhead-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  