  export default "import React from 'react'\nimport { Input, Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  color: string\n  width: number\n  blur: number\n  opacity: number\n}\n\nexport const defaults: State = {\n  color: '#4943a3',\n  width: 10,\n  blur: 1,\n  opacity: 0.5,\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = defaults\n\n  notifyChange() {\n    this.props.onChange({\n      ...this.state,\n    })\n  }\n\n  onColorChanged = (e: any) => {\n    this.setState({ color: e.target.value }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onWidthChanged = (width: number) => {\n    this.setState({ width }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onBlurChanged = (blur: number) => {\n    this.setState({ blur }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onOpacityChanged = (opacity: number) => {\n    this.setState({ opacity }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card\n        title=\"Settings\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 320 }}\n      >\n        <Row align=\"middle\">\n          <Col span={6}>color</Col>\n          <Col span={14}>\n            <Input\n              type=\"color\"\n              value={this.state.color}\n              style={{ width: '100%' }}\n              onChange={this.onColorChanged}\n            />\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6}>width</Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={20}\n              step={1}\n              value={this.state.width}\n              onChange={this.onWidthChanged}\n            />\n          </Col>\n          <Col span={2}>\n            <div className=\"slider-value\">{this.state.width.toFixed(2)}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={6}>blur</Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={20}\n              step={1}\n              value={this.state.blur}\n              onChange={this.onBlurChanged}\n            />\n          </Col>\n          <Col span={2}>\n            <div className=\"slider-value\">{this.state.blur.toFixed(2)}</div>\n          </Col>\n        </Row>\n\n        <Row align=\"middle\">\n          <Col span={6}>opacity</Col>\n          <Col span={14}>\n            <Slider\n              min={0.05}\n              max={1}\n              step={0.05}\n              value={this.state.opacity}\n              onChange={this.onOpacityChanged}\n            />\n          </Col>\n          <Col span={2}>\n            <div className=\"slider-value\">{this.state.opacity.toFixed(2)}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  