  export default "import React from 'react'\nimport { Graph, Interp } from '@antv/x6'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const edge = graph.addEdge({\n      source: { x: 30, y: 80 },\n      target: { x: 430, y: 80 },\n      vertices: [{ x: 230, y: 160 }],\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    edge.appendLabel({\n      attrs: {\n        text: {\n          text: '0.25',\n        },\n      },\n      position: {\n        distance: 0.25,\n      },\n    })\n\n    edge.appendLabel({\n      attrs: {\n        text: {\n          text: '150',\n        },\n      },\n      position: {\n        distance: 150,\n      },\n    })\n\n    edge.appendLabel({\n      attrs: {\n        text: {\n          text: '-100',\n        },\n      },\n      position: {\n        distance: -100,\n      },\n    })\n\n    let currentTransitions = 0\n    let oscillateToggle = false\n\n    function contract() {\n      edge.transition(\n        'source',\n        { x: 130, y: 80 },\n        {\n          delay: 1000,\n          duration: 4000,\n          timing: (time) => {\n            return time <= 0.5 ? 2 * time : 2 * (1 - time)\n          },\n          interp: Interp.object,\n        },\n      )\n\n      edge.transition(\n        'target',\n        { x: 330, y: 80 },\n        {\n          delay: 1000,\n          duration: 4000,\n          timing: (time) => {\n            return time <= 0.5 ? 2 * time : 2 * (1 - time)\n          },\n          interp: Interp.object,\n        },\n      )\n\n      oscillateToggle = true\n    }\n\n    function oscillate() {\n      edge.transition(\n        'source',\n        { x: 30, y: 160 },\n        {\n          delay: 1000,\n          duration: 4000,\n          timing: (time) => {\n            return time <= 0.5 ? 2 * time : 2 * (1 - time)\n          },\n          interp: Interp.object,\n        },\n      )\n\n      edge.transition(\n        'vertices/0',\n        { x: 230, y: 80 },\n        {\n          delay: 1000,\n          duration: 4000,\n          timing: (time) => {\n            return time <= 0.5 ? 2 * time : 2 * (1 - time)\n          },\n          interp: Interp.object,\n        },\n      )\n\n      edge.transition(\n        'target',\n        { x: 430, y: 160 },\n        {\n          delay: 1000,\n          duration: 4000,\n          timing: (time) => {\n            return time <= 0.5 ? 2 * time : 2 * (1 - time)\n          },\n          interp: Interp.object,\n        },\n      )\n\n      oscillateToggle = false\n    }\n\n    edge.on('transition:start', () => {\n      currentTransitions += 1\n    })\n\n    edge.on('transition:complete', () => {\n      currentTransitions -= 1\n\n      if (currentTransitions === 0) {\n        if (oscillateToggle) {\n          oscillate()\n        } else {\n          contract()\n        }\n      }\n    })\n\n    contract()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"label-position\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  