  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    const source = graph.addNode({\n      x: 40,\n      y: 40,\n      width: 100,\n      height: 40,\n      label: 'source',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n      tools: [\n        {\n          name: 'button-remove',\n          args: {\n            x: '100%',\n            y: 0,\n            offset: { x: -10, y: 10 },\n          },\n        },\n      ],\n    })\n\n    const target = graph.addNode({\n      x: 120,\n      y: 160,\n      width: 100,\n      height: 40,\n      label: 'target',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n\n    graph.on('node:mouseenter', ({ node }) => {\n      if (node === target) {\n        node.addTools({\n          name: 'button-remove',\n          args: {\n            x: 0,\n            y: 0,\n            offset: { x: 10, y: 10 },\n          },\n        })\n      }\n    })\n\n    graph.on('node:mouseleave', ({ node }) => {\n      if (node === target) {\n        node.removeTools()\n      }\n    })\n\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"button-remove-tool-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  