  export default "import React from 'react'\nimport { Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  x: number\n  y: number\n  angle: number\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    x: 0.6,\n    y: 32,\n    angle: 45,\n  }\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onXChanged = (x: number) => {\n    this.setState({ x }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onYChanged = (y: number) => {\n    this.setState({ y }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onAngleChanged = (angle: number) => {\n    this.setState({ angle }, () => {\n      this.notifyChange()\n    })\n  }\n\n  render() {\n    return (\n      <Card title=\"Args\" size=\"small\" bordered={false} style={{ width: 320 }}>\n        <Row align=\"middle\">\n          <Col span={5} style={{ textAlign: 'right', paddingRight: 8 }}>\n            x\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={0.99}\n              step={0.01}\n              value={this.state.x}\n              onChange={this.onXChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.x}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5} style={{ textAlign: 'right', paddingRight: 8 }}>\n            y\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={-20}\n              max={140}\n              step={1}\n              value={this.state.y}\n              onChange={this.onYChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.y}</div>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5} style={{ textAlign: 'right', paddingRight: 8 }}>\n            angle\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={0}\n              max={360}\n              step={1}\n              value={this.state.angle}\n              onChange={this.onAngleChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.angle}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  