  export default "import React from 'react'\nimport { Radio, Slider, Card, Row, Col } from 'antd'\n\nexport interface Props {\n  onChange: (state: State) => void\n}\n\nexport interface State {\n  position: string\n  offset: number\n}\n\nexport class Settings extends React.Component<Props, State> {\n  state: State = {\n    position: 'outside',\n    offset: 15,\n  }\n\n  notifyChange() {\n    this.props.onChange(this.state)\n  }\n\n  onOffsetChanged = (offset: number) => {\n    this.setState({ offset }, () => {\n      this.notifyChange()\n    })\n  }\n\n  onPositionChange = (e: any) => {\n    this.setState(\n      {\n        position: e.target.value,\n      },\n      () => {\n        this.notifyChange()\n      },\n    )\n  }\n\n  render() {\n    const radioStyle = {\n      display: 'block',\n      height: '36px',\n      lineHeight: '36px',\n    }\n\n    return (\n      <Card\n        title=\"Port Label Position\"\n        size=\"small\"\n        bordered={false}\n        style={{ width: 240 }}\n      >\n        <Row\n          align=\"middle\"\n          justify=\"center\"\n          style={{\n            borderBottom: '1px solid #f0f0f0',\n            paddingBottom: 16,\n            marginBottom: 16,\n          }}\n        >\n          <Col>\n            <Radio.Group\n              value={this.state.position}\n              onChange={this.onPositionChange}\n            >\n              <Radio style={radioStyle} value={'inside'}>\n                inside\n              </Radio>\n              <Radio style={radioStyle} value={'outside'}>\n                outside\n              </Radio>\n              <Radio style={radioStyle} value={'insideOriented'}>\n                insideOriented\n              </Radio>\n              <Radio style={radioStyle} value={'outsideOriented'}>\n                outsideOriented\n              </Radio>\n            </Radio.Group>\n          </Col>\n        </Row>\n        <Row align=\"middle\">\n          <Col span={5} style={{ textAlign: 'right', paddingRight: 16 }}>\n            offset\n          </Col>\n          <Col span={14}>\n            <Slider\n              min={-30}\n              max={30}\n              step={1}\n              value={this.state.offset}\n              onChange={this.onOffsetChanged}\n            />\n          </Col>\n          <Col span={1} offset={1}>\n            <div className=\"slider-value\">{this.state.offset}</div>\n          </Col>\n        </Row>\n      </Card>\n    )\n  }\n}\n";;
  