  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport './index.less'\n\nconst data = {\n  nodes: [\n    {\n      id: 'node1',\n      shape: 'rect',\n      x: 40,\n      y: 40,\n      width: 100,\n      height: 40,\n      label: 'hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    },\n    {\n      id: 'node2',\n      shape: 'rect',\n      x: 160,\n      y: 180,\n      width: 100,\n      height: 40,\n      label: 'world',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    },\n  ],\n  edges: [\n    {\n      shape: 'edge',\n      source: 'node1',\n      target: 'node2',\n      label: 'x6',\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    },\n  ],\n}\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n\n  componentDidMount() {\n    const graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n      grid: {\n        visible: true,\n        type: 'doubleMesh',\n        args: [\n          {\n            color: '#eee', // 主网格线颜色\n            thickness: 1, // 主网格线宽度\n          },\n          {\n            color: '#ddd', // 次网格线颜色\n            thickness: 1, // 次网格线宽度\n            factor: 4, // 主次网格线间隔\n          },\n        ],\n      },\n    })\n\n    graph.fromJSON(data)\n    graph.centerContent()\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"backgournd-grid-app\">\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  