  export default "import React from 'react'\nimport { Graph } from '@antv/x6'\nimport { Snapline } from '@antv/x6-plugin-snapline'\nimport { Settings, State } from './settings'\nimport './index.less'\n\nexport default class Example extends React.Component {\n  private container: HTMLDivElement\n  private graph: Graph\n\n  componentDidMount() {\n    this.graph = new Graph({\n      container: this.container,\n      background: {\n        color: '#F2F7FA',\n      },\n    })\n\n    this.graph.use(\n      new Snapline({\n        enabled: true,\n        clean: false,\n      }),\n    )\n\n    this.graph.addNode({\n      x: 200,\n      y: 100,\n      width: 100,\n      height: 40,\n      label: 'Drag Me',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const source = this.graph.addNode({\n      x: 32,\n      y: 32,\n      width: 100,\n      height: 40,\n      label: 'Hello',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n          rx: 6,\n          ry: 6,\n        },\n      },\n    })\n\n    const target = this.graph.addNode({\n      shape: 'circle',\n      x: 160,\n      y: 180,\n      width: 60,\n      height: 60,\n      label: 'World',\n      attrs: {\n        body: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n          fill: '#fff',\n        },\n      },\n    })\n\n    this.graph.addEdge({\n      source,\n      target,\n      attrs: {\n        line: {\n          stroke: '#8f8f8f',\n          strokeWidth: 1,\n        },\n      },\n    })\n  }\n\n  onSnaplineChanged = (options: State) => {\n    this.graph.setSnaplineTolerance(options.tolerance)\n    this.graph.setSnaplineFilter(options.filter)\n\n    if (options.sharp) {\n      this.graph.enableSharpSnapline()\n    } else {\n      this.graph.disableSharpSnapline()\n    }\n\n    if (options.resizing) {\n      this.graph.enableSnaplineOnResizing()\n    } else {\n      this.graph.disableSnaplineOnResizing()\n    }\n  }\n\n  refContainer = (container: HTMLDivElement) => {\n    this.container = container\n  }\n\n  render() {\n    return (\n      <div className=\"snapline-app\">\n        <div className=\"app-side\">\n          <Settings onChange={this.onSnaplineChanged} />\n        </div>\n        <div className=\"app-content\" ref={this.refContainer} />\n      </div>\n    )\n  }\n}\n";;
  